import re

def detect_secrets_in_tool_use(response):
    patterns = [
        r'\b[A-Za-z0-9]{32,}\b',  # API keys
        r'(sk-|gpt-)\w{48}',       # OpenAI/Claude keys
        r'AKIA[0-9A-Z]{16}'         # AWS keys
    ]
    for block in response.content:
        if block.type == 'tool_use':
            input_data = block.input
            for pattern in patterns:
                if re.search(pattern, str(input_data)):
                    return {'leak': True, 'pattern': pattern, 'data': input_data}
    return {'leak': False}

