import re
from anthropic.types import ToolUseBlock

def sanitize_tool_input(tool_input: dict) -> dict:
    def recursive_sanitize(obj):
        if isinstance(obj, dict):
            return {k: recursive_sanitize(v) for k, v in obj.items()}
        elif isinstance(obj, list):
            return [recursive_sanitize(item) for item in obj]
        elif isinstance(obj, str):
            # Redact common secrets
            obj = re.sub(r'(sk-|gpt-)\w{48}', '[REDACTED_KEY]', obj)
            obj = re.sub(r'AKIA[0-9A-Z]{16}', '[REDACTED_AWS_KEY]', obj)
            return obj
        return obj
    return recursive_sanitize(tool_input)

