async function injectVaultCredentials(toolInput: any): Promise<any> {
  if (toolInput.apiKey) {
    const vaultToken = await fetchVaultToken(toolInput.service);
    toolInput.apiKey = vaultToken;  // Ephemeral token
    delete toolInput.secret;  // Remove persistent secrets
  }

  // Validate no secrets remain
  const hasSecrets = /sk-|AKIA[0-9A-Z]{16}/.test(JSON.stringify(toolInput));
  if (hasSecrets) {
    throw new Error('Secrets detected after sanitization');
  }

  return toolInput;
}
